package com.parkflow.mall.gateway.controller;
import com.parkflow.mall.gateway.merchant.MerchantServiceProxy; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*;
@RestController public class MerchantGatewayController {private final MerchantServiceProxy proxy;public MerchantGatewayController(MerchantServiceProxy p){proxy=p;}@PostMapping("/api/merchant/validations") public ResponseEntity<String> validate(@RequestHeader(value="Authorization",required=false)String auth,@RequestBody String body){return proxy.validate(auth,body);}@GetMapping("/api/merchant/validations") public ResponseEntity<String> history(@RequestHeader(value="Authorization",required=false)String auth,@RequestParam String sessionId){return proxy.history(auth,sessionId);}}
